//  STATE
// ══════════════════════════════════════════════════════════
let currentUser=null;
let sessionData={};
let sessionQList=[];
let sessionQIdx=0;
let sessionAnswers=[];
let sessionScores=[];

// ══════════════════════════════════════════════════════════
//  STORAGE
// ══════════════════════════════════════════════════════════
function getUsers(){return JSON.parse(localStorage.getItem('iai_users')||'{}');}
function saveUsers(u){localStorage.setItem('iai_users',JSON.stringify(u));}
function getHistory(uid){return JSON.parse(localStorage.getItem('iai_hist_'+uid)||'[]');}
function saveHistory(uid,h){localStorage.setItem('iai_hist_'+uid,JSON.stringify(h));}

function genLoginId(fname){return fname.toUpperCase().replace(/[^A-Z]/g,'').slice(0,4)+'-'+Math.floor(1000+Math.random()*9000);}

function showPage(id){document.querySelectorAll('.page').forEach(p=>p.classList.remove('active'));document.getElementById(id).classList.add('active');}
function showLogin(){showPage('loginPage');}
function showRegister(){showPage('registerPage');}

function validate(fgId,isValid){const fg=document.getElementById(fgId);if(!fg)return;if(isValid)fg.classList.remove('has-error');else fg.classList.add('has-error');return isValid;}

// ══════════════════════════════════════════════════════════
//  REGISTER
// ══════════════════════════════════════════════════════════
function registerUser(){
  const fname=document.getElementById('reg-fname').value.trim();
  const lname=document.getElementById('reg-lname').value.trim();
  const email=document.getElementById('reg-email').value.trim();
  const phone=document.getElementById('reg-phone').value.trim();
  const college=document.getElementById('reg-college').value.trim();
  const degree=document.getElementById('reg-degree').value.trim();
  const year=document.getElementById('reg-year').value;
  const pass=document.getElementById('reg-pass').value;
  let ok=true;
  if(!fname)ok=validate('fg-fname',false)&&ok;else validate('fg-fname',true);
  if(!lname)ok=validate('fg-lname',false)&&ok;else validate('fg-lname',true);
  if(!email||!/^[^@]+@[^@]+\.[^@]+$/.test(email)){ok=validate('fg-email',false)&&ok;}else validate('fg-email',true);
  if(!phone||phone.replace(/\D/g,'').length<10){ok=validate('fg-phone',false)&&ok;}else validate('fg-phone',true);
  if(!college)ok=validate('fg-college',false)&&ok;else validate('fg-college',true);
  if(!degree)ok=validate('fg-degree',false)&&ok;else validate('fg-degree',true);
  if(!year)ok=validate('fg-year',false)&&ok;else validate('fg-year',true);
  if(!pass||pass.length<6){ok=validate('fg-pass',false)&&ok;}else validate('fg-pass',true);
  if(!ok)return;
  const loginId=genLoginId(fname);
  const users=getUsers();
  if(Object.values(users).find(u=>u.email===email)){validate('fg-email',false);document.querySelector('#fg-email .form-error').textContent='Email already registered';return;}
  const user={loginId,fname,lname,email,phone,college,degree,year,pass,joined:new Date().toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'})};
  users[loginId]=user;saveUsers(users);
  document.getElementById('loginIdDisplay').textContent=loginId;
  document.getElementById('loginIdBox').style.display='block';
  setTimeout(()=>{currentUser=user;loadDashboard();showPage('dashboardPage');},2200);
}

// ══════════════════════════════════════════════════════════
//  LOGIN
// ══════════════════════════════════════════════════════════
function loginUser(){
  const lid=document.getElementById('login-id').value.trim().toUpperCase();
  const pass=document.getElementById('login-pass').value;
  const users=getUsers();
  const user=users[lid];
  if(!user){validate('fg-lid',false);return;}else validate('fg-lid',true);
  if(user.pass!==pass){validate('fg-lpass',false);return;}else validate('fg-lpass',true);
  currentUser=user;loadDashboard();showPage('dashboardPage');
}

function logoutUser(){currentUser=null;document.getElementById('login-id').value='';document.getElementById('login-pass').value='';showPage('loginPage');}

// ══════════════════════════════════════════════════════════
//  DASHBOARD
// ══════════════════════════════════════════════════════════
function loadDashboard(){
  const u=currentUser;
  const initials=(u.fname[0]+(u.lname||'')[0]||'').toUpperCase();
  document.getElementById('topbarAvatar').textContent=initials;
  document.getElementById('topbarName').textContent=u.fname;
  document.getElementById('welcomeMsg').textContent='Welcome back, '+u.fname+'! 👋';
  document.getElementById('welcomeSub').textContent='Logged in as '+u.loginId+'. Ready for your next session?';
  document.getElementById('profileAvatar').textContent=initials;
  document.getElementById('profileName').textContent=u.fname+' '+u.lname;
  document.getElementById('profileCollege').textContent=u.college;
  document.getElementById('profileLoginId').textContent=u.loginId;
  document.getElementById('profileEmail').textContent=u.email;
  document.getElementById('profilePhone').textContent=u.phone;
  document.getElementById('profileCollegeFull').textContent=u.college;
  document.getElementById('profileDegree').textContent=u.degree;
  document.getElementById('profileYear').textContent=u.year;
  document.getElementById('profileJoined').textContent=u.joined;
  renderHistory();renderStats();
}

function renderStats(){
  const hist=getHistory(currentUser.loginId);
  document.getElementById('statTotal').textContent=hist.length;
  if(hist.length===0){document.getElementById('statBest').textContent='—';document.getElementById('statAvg').textContent='—';}
  else{const scores=hist.map(h=>h.score);document.getElementById('statBest').textContent=Math.max(...scores).toFixed(1);document.getElementById('statAvg').textContent=(scores.reduce((a,b)=>a+b,0)/scores.length).toFixed(1);}
  const now=new Date();const weekAgo=new Date(now-7*24*60*60*1000);
  document.getElementById('statWeek').textContent=hist.filter(h=>new Date(h.ts)>weekAgo).length;
}

function histItemHTML(h){
  const dc=h.difficulty==='basic'?'diff-b':h.difficulty==='intermediate'?'diff-m':'diff-h';
  const dl={basic:'Basic',intermediate:'Intermediate',hard:'Hard'}[h.difficulty]||h.difficulty;
  const ic=h.category==='it'?'hi-icon-it':'hi-icon-nit';
  const sc=h.score>=8?'var(--green)':h.score>=6?'var(--gold)':'var(--red)';
  const d=new Date(h.ts);
  const ds=d.toLocaleDateString('en-IN',{day:'numeric',month:'short',year:'numeric'})+' '+d.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'});
  return`<div class="history-item"><div class="hi-icon ${ic}">${h.emoji||'🎤'}</div><div class="hi-info"><h4>${h.role} <span class="diff-badge ${dc}">${dl}</span></h4><p>${h.type==='technical'?'Technical Round':h.type==='hr'?'HR Round':'Mixed Round'} · ${h.qCount||15} questions</p></div><div class="hi-right"><div class="hi-score" style="color:${sc}">${h.score.toFixed(1)}</div><div class="hi-date">${ds}</div></div></div>`;
}

function renderHistory(){
  const hist=getHistory(currentUser.loginId);
  const r=document.getElementById('recentList'),f=document.getElementById('fullHistoryList');
  const empty=`<div class="empty-state"><div class="es-icon">🎤</div><h4>No sessions yet</h4><p>Start your first 15-question interview session to build your history.</p></div>`;
  if(hist.length===0){r.innerHTML=empty;f.innerHTML=empty;return;}
  r.innerHTML=[...hist].reverse().slice(0,4).map(h=>histItemHTML(h)).join('');
  f.innerHTML=[...hist].reverse().map(h=>histItemHTML(h)).join('');
}

function switchTab(name,btn){
  document.querySelectorAll('.dash-section').forEach(s=>s.classList.remove('active'));
  document.getElementById('tab-'+name).classList.add('active');
  document.querySelectorAll('.topbar-tab').forEach(b=>b.classList.remove('active'));
  if(btn)btn.classList.add('active');
}

